
%% Saving the location of seeds for the curret slice
commandwindow
% init_seeds = seeds;
% save ( ['init_seeds_slice',num2str(slice),'.mat'],'init_seeds' )
if exist('init_seeds.mat','file')
    load init_seeds
else
    init_seeds = zeros(size(skull_Stripped_Image,1)*size(skull_Stripped_Image,2), 2, size(qmap,3));
    save('init_seeds.mat','init_seeds')
end
% init_seeds(:,:,slice_number) = seeds;
% save ( 'init_seeds.mat','init_seeds' )

%% Taking out the regions from each slice and saving it
commandwindow
if exist('graphcuts_segmented3d_MRI.mat','file')
    load graphcuts_segmented3d_MRI
else
    graphcuts_segmented3d_qMRI = zeros(size(qmap));
    save('graphcuts_segmented3d_MRI.mat','graphcuts_segmented3d_MRI')
end

binary_SEG = false(size(skull_Stripped_Image));
binary_SEG(segind==1) = true; % assuming that segind is 1 at PUTAMEN OR CAUDATE and 2 at bkg
conn_comp = bwconncomp(binary_SEG);

seeds_PUT_CAUDATE = false(size(skull_Stripped_Image));
seeds_PUT_CAUDATE( nonzeros(seeds(:,1)) ) = true; % first column of seeds is assumed to have indices of PUTAMEN OR CAUDATE seeds

current_slice_PUTorCAUDATE = false(size(skull_Stripped_Image));
for i = 1:conn_comp.NumObjects
    current_conn_comp = false(size(skull_Stripped_Image));
    dummy = conn_comp.PixelIdxList{i};
    current_conn_comp(dummy) = true;
    if any( any(current_conn_comp&seeds_PUT_CAUDATE) )
        current_slice_PUTorCAUDATE(current_conn_comp) = true;
        current_slice_PUTorCAUDATE = imfill(current_slice_PUTorCAUDATE, 'holes');
    end
end

% graphcuts_segmented3d_MRI(:,:,slice_number) = current_slice_PUTorCAUDATE;

clear binary_SEG conn_comp seeds_PUT_CAUDATE current_conn_comp dummy
save ( 'graphcuts_segmented3d_MRI.mat','graphcuts_segmented3d_MRI' )
figure, imshow(graphcuts_segmented3d_MRI(:,:,slice_number), 'initialmagnification', 'fit'), title('Segmented ROI (removed other structures not connected to seeds)')
set(gcf, 'units', 'normalized', 'outerposition', [0 0 1 1])


mask=boundarymask(graphcuts_segmented3d_MRI(:,:,slice_number));%computes a mask that represents the region boundaries.mask is true at boundary locations and false at non-boundary locations.
% mask=bwprim(graphcuts_segmented3d_MRI(:,:,slice_number));
figure,imshow(mask);
mask=imcomplement(mask);
figure,imshow(mask);
set(gcf, 'units','normalized','outerposition',[0 0 1 1]);%show full screen size
finalsegonmri=immultiply(skull_Stripped_Image,mask);
figure,
imshow(finalsegonmri,[]);
set(gcf, 'units','normalized','outerposition',[0 0 1 1]);%show full screen size









